import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import matchesSearchQuery from './matchesSearchQuery';

describe('matchesSearchQuery', () => {
  // Happy path: query is found within note string (case‑insensitive)
  it('should handle happy path where query is present in note', () => {
    const note = 'This is a sample note about JavaScript testing.';
    const query = 'javascript';
    const result = matchesSearchQuery(note, query);
    expect(result).toBe(true);
  });

  // Edge case: empty query should match any note (treated as no filtering)
  it('should handle edge case where query is an empty string', () => {
    const note = 'Any content should match when query is empty.';
    const query = '';
    const result = matchesSearchQuery(note, query);
    expect(result).toBe(true);
  });

  // Null / undefined / falsy inputs
  it('should handle null/empty inputs gracefully', () => {
    // note is null
    expect(matchesSearchQuery(null as any, 'test')).toBe(false);
    // query is null
    expect(matchesSearchQuery('some note', null as any)).toBe(false);
    // both are undefined
    expect(matchesSearchQuery(undefined as any, undefined as any)).toBe(false);
    // note is empty string, query non‑empty
    expect(matchesSearchQuery('', 'test')).toBe(false);
    // note and query are both empty strings (covered by edge case but tested again)
    expect(matchesSearchQuery('', '')).toBe(true);
  });
});

